import{_ as e,a as t,b as n,c as i}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as d,o as r,c as p,a2 as u}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup dan Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/redundant-backup-and-read-source.md","filePath":"ms-MY/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"ms-MY/Other/redundant-backup-and-read-source.md"};function c(s,a,h,k,o,b){return r(),p("div",null,[...a[0]||(a[0]=[u('<h1 id="redundant-backup-dan-read-source-switching" tabindex="-1">Redundant Backup dan Read Source Switching <a class="header-anchor" href="#redundant-backup-dan-read-source-switching" aria-label="Permalink to &quot;Redundant Backup dan Read Source Switching&quot;">​</a></h1><p>Redundant backup menyimpan extra copy untuk file yang sudah di-upload.</p><p>Kedua-dua primary file dan backup file boleh digunakan sebagai read sources. Visitors biasanya tidak melihat perbezaan. Perbezaannya hanya storage channel mana yang serve file.</p><h2 id="fungsi-redundant-backup" tabindex="-1">Fungsi Redundant Backup <a class="header-anchor" href="#fungsi-redundant-backup" aria-label="Permalink to &quot;Fungsi Redundant Backup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Store an extra copy</td><td>Back up files ke upload channel lain untuk mengurangkan risiko single channel failure.</td></tr><tr><td>Switch read source</td><td>Selepas backup berjaya, switch file reads antara primary channel dan backup channel.</td></tr><tr><td>Single-file backup</td><td>Back up satu file dari file details page.</td></tr><tr><td>Batch backup</td><td>Pilih beberapa files dalam admin page dan back up bersama.</td></tr><tr><td>Global redundant backup</td><td>Back up files mengikut folder dari Other Settings.</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>Entry ini paling sesuai untuk menambah backups kepada folder atau semua files secara bulk.</p><p>Backup channel boleh dipilih secara manual, atau anda boleh memilih automatic switching dan membiarkan ImgBed mencari backup channel yang sesuai.</p><h2 id="backup-dari-file-details" tabindex="-1">Backup Dari File Details <a class="header-anchor" href="#backup-dari-file-details" aria-label="Permalink to &quot;Backup Dari File Details&quot;">​</a></h2><p>Buka file details page dalam admin panel dan klik backup.</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>Ini paling sesuai untuk back up satu important file on demand.</p><p>Selepas backup berjaya, file details page menunjukkan available read sources.</p><h2 id="batch-backup-mengikut-selection" tabindex="-1">Batch Backup Mengikut Selection <a class="header-anchor" href="#batch-backup-mengikut-selection" aria-label="Permalink to &quot;Batch Backup Mengikut Selection&quot;">​</a></h2><p>Dalam admin panel, pilih beberapa files dan run batch backup.</p><p><img src="'+n+'" alt="Batch backup" loading="lazy"></p><p>Ini sesuai untuk memproses sekumpulan files.</p><p>Selection backup, file details backup dan redundant backup di bawah Other Settings semuanya menggunakan backup system yang sama. Ia cuma entry points yang berbeza.</p><h2 id="switching-read-source-selepas-backup" tabindex="-1">Switching Read Source Selepas Backup <a class="header-anchor" href="#switching-read-source-selepas-backup" aria-label="Permalink to &quot;Switching Read Source Selepas Backup&quot;">​</a></h2><p>Selepas backup complete, file details page membolehkan anda switch read source:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>Read dari original upload channel.</td></tr><tr><td>Backup channel</td><td>Read dari backup channel.</td></tr></tbody></table><p><img src="'+i+'" alt="Switch read source after backup" loading="lazy"></p><p>Visitors tidak perlu tahu sama ada file served dari primary atau backup channel.</p><p>Read source yang anda pilih menjadi preferred source untuk file access selepas itu.</p><h2 id="bila-backup-diskip" tabindex="-1">Bila Backup Diskip <a class="header-anchor" href="#bila-backup-diskip" aria-label="Permalink to &quot;Bila Backup Diskip&quot;">​</a></h2><p>Kes berikut akan diskip semasa backup. Ia bukan errors.</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>File yang sudah ada backup tidak akan dibackup sekali lagi.</td></tr><tr><td>Primary dan backup channels sama</td><td>Backup mesti disimpan dalam channel lain untuk bermakna.</td></tr><tr><td>No usable backup channel</td><td>Tiada alternative channel yang sesuai.</td></tr></tbody></table><p>Ringkasnya: backups mesti pergi ke channel lain, dan files yang sudah backed-up tidak menggunakan extra space lagi.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>Channel yang digunakan semasa file pertama kali di-upload.</td></tr><tr><td>Backup channel</td><td>Channel yang menyimpan redundant copy.</td></tr><tr><td>Primary read source</td><td>File sedang dibaca dari primary channel.</td></tr><tr><td>Backup read source</td><td>File sedang dibaca dari backup channel.</td></tr></tbody></table><p>Primary dan backup read sources mempunyai user-facing behavior yang sama.</p><p>Selagi backup file tersedia, images, videos dan download links terus berfungsi selepas switch ke backup read source.</p><h2 id="apa-berlaku-apabila-file-dipadam" tabindex="-1">Apa Berlaku Apabila File Dipadam <a class="header-anchor" href="#apa-berlaku-apabila-file-dipadam" aria-label="Permalink to &quot;Apa Berlaku Apabila File Dipadam&quot;">​</a></h2><p>Apabila file dipadam, ImgBed delete primary file dan backup file.</p>',37)])])}const f=d(l,[["render",c]]);export{y as __pageData,f as default};
